		if x == 1 {
			return 0
		}
		if depth, exists := depthMemo[x]; exists {
			return depth
		}
		pop := getPopcount(x)
		depth := 1 + computeDepth(pop)
		depthMemo[x] = depth
		return depth
	}

	depths := make([]int64, len(nums))
	for i := range nums {
		depths[i] = computeDepth(nums[i])
